2. Display Math 行间公式
mjx-container[overflow="scroll"][display] {
  overflow: auto clip;
  min-width: initial !important;
}

mjx-container[overflow="truncate"][display] {
  overflow: hidden clip;
  min-width: initial !important;
}

mjx-container[display] {
  display: block;
  text-align: center;
  justify-content: center;
  margin: .7em 0;
  padding: .3em 2px;
}

mjx-container[display][width="full"] {
  display: flex;
}

mjx-container[justify="left"] {
  text-align: left;
  justify-content: left;
}

mjx-container[justify="right"] {
  text-align: right;
  justify-content: right;
}

mjx-container[jax="SVG"] {
  direction: ltr;
  white-space: nowrap;
}

mjx-container[jax="SVG"] > svg {
  overflow: visible;
  min-height: 1px;
  min-width: 1px;
}

mjx-container[jax="SVG"] > svg a {
  fill: blue;
  stroke: blue;
}

rect[data-sre-highlighter-added]:has(+ .mjx-selected), rect[data-sre-highlighter-bbox].mjx-selected {
  stroke: black;
  stroke-width: 80px;
}

@media (prefers-color-scheme: dark) {
  rect[data-sre-highlighter-added]:has(+ .mjx-selected), rect[data-sre-highlighter-bbox].mjx-selected {
    stroke: #C8C8C8;
  }
}

mjx-container[jax="SVG"] mjx-break {
  white-space: normal;
  line-height: 0;
  clip-path: rect(0 0 0 0);
  font-family: MJX-ZERO ! important;
}

mjx-break[size="0"] {
  letter-spacing: -0.999em;
}

mjx-break[size="1"] {
  letter-spacing: -0.889em;
}

mjx-break[size="2"] {
  letter-spacing: -0.833em;
}

mjx-break[size="3"] {
  letter-spacing: -0.778em;
}

mjx-break[size="4"] {
  letter-spacing: -0.722em;
}

mjx-break[size="5"] {
  letter-spacing: -0.667em;
}

mjx-container[jax="SVG"] mjx-break[newline]::before {
  white-space: pre;
  content: "\A";
}

mjx-break[newline] + svg[width="0.054ex"] {
  margin-right: -1px;
}

mjx-break[prebreak] {
  letter-spacing: -.999em;
}

@font-face /* zero */ {
  font-family: MJX-ZERO;
  src: url(data:application/x-font-woff;charset=utf-8;base64,) format("woff");
}

g[data-mml-node="merror"] > g {
  fill: red;
  stroke: red;
}

g[data-mml-node="merror"] > rect[data-background] {
  fill: yellow;
  stroke: none;
}

g[data-mml-node="mtable"] > line[data-line], svg[data-table] > g > line[data-line] {
  stroke-width: 70px;
  fill: none;
}

g[data-mml-node="mtable"] > rect[data-frame], svg[data-table] > g > rect[data-frame] {
  stroke-width: 70px;
  fill: none;
}

g[data-mml-node="mtable"] > .mjx-dashed, svg[data-table] > g > .mjx-dashed {
  stroke-dasharray: 140;
}

g[data-mml-node="mtable"] > .mjx-dotted, svg[data-table] > g > .mjx-dotted {
  stroke-linecap: round;
  stroke-dasharray: 0,140;
}

g[data-mml-node="mtable"] > g > svg {
  overflow: visible;
}

[jax="SVG"] mjx-tool {
  display: inline-block;
  position: relative;
  width: 0;
  height: 0;
}

[jax="SVG"] mjx-tool > mjx-tip {
  position: absolute;
  top: 0;
  left: 0;
}

mjx-tool > mjx-tip {
  display: inline-block;
  line-height: 0;
  padding: .2em;
  border: 1px solid #888;
  background-color: #F8F8F8;
  color: black;
  box-shadow: 2px 2px 5px #AAAAAA;
}

g[data-mml-node="maction"][data-toggle] {
  cursor: pointer;
}

mjx-status {
  display: block;
  position: fixed;
  left: 1em;
  bottom: 1em;
  min-width: 25%;
  padding: .2em .4em;
  border: 1px solid #888;
  font-size: 90%;
  background-color: #F8F8F8;
  color: black;
}

g[data-mjx-collapsed] {
  fill: #55F;
}

@media (prefers-color-scheme: dark) /* svg maction */ {
  mjx-tool > mjx-tip {
    background-color: #303030;
      color: #E0E0E0;
      box-shadow: 2px 2px 5px #000;
  }
  mjx-status {
    background-color: #303030;
      color: #E0E0E0;
  }
  g[data-mjx-collapsed] {
    fill: #88F;
  }
}

foreignObject[data-mjx-xml] {
  font-family: initial;
  line-height: normal;
  overflow: visible;
}

foreignObject[data-mjx-html] {
  overflow: visible;
}

mjx-measure-xml {
  position: absolute;
  left: 0;
  top: 0;
  display: inline-block;
  line-height: normal;
  white-space: normal;
}

mjx-html {
  display: inline-block;
  line-height: normal;
  text-align: initial;
  white-space: initial;
}

mjx-html-holder {
  display: block;
  position: absolute;
  top: 0;
  left: 0;
  bottom: 0;
  right: 0;
}

mjx-container[jax="SVG"] path[data-c], mjx-container[jax="SVG"] use[data-c] {
  stroke-width: 3;
}


Font TypesUse \mathbb or \Bbb to display blackboard bold characters. This font is often used to represent real numbers, integers, rational numbers, and complex numbers.


Use \mathbf to display bold text


Use \mathrm to display Roman fonts


Use \mathscr to display cursive fonts


Use \mathfrak to display Fraktur letters (a type of German font)


Use \mathtt to display printer fonts


